import { Box, Button, Container, Divider, FormControl, FormControlLabel, FormLabel, Grid, makeStyles, Paper, Radio, RadioGroup, TextField, Typography } from '@material-ui/core';
import { AddRounded, CheckBox } from '@material-ui/icons';
import React from 'react';

const useStyle = makeStyles(theme => {
  return {
    paper: {
      padding: theme.spacing(2),
      borderTop: '10px solid #162276'
    },
    quizPaper: {
      padding: theme.spacing(2),
      borderLeft: '10px solid #162276'
    }
  }
})

const CreateQuiz = () => {
  const classes = useStyle()


  return (
    <Container>
      <Box mb={2}>
        Create Quiz
        <Paper className={classes.paper}>
          <TextField placeholder='Quiz title' fullWidth />
          <TextField placeholder='Description' fullWidth />
        </Paper>
      </Box>
      <Box mb={2}>
        <Paper className={classes.quizPaper}>
          <TextField placeholder='Question' fullWidth />
          <FormControl component="fieldset">
            <RadioGroup aria-label="gender" name="gender1" >
              <FormControlLabel value="female" control={<Radio />} label="Option" />
            </RadioGroup>
          </FormControl>
          <Box mt={3}>
          <Divider />
            <Typography variant='caption' onClick={() => {console.log('something')}}>Set correct answer</Typography>
          </Box>
        </Paper>
      </Box>
    </Container>
  );
}

export default CreateQuiz;
